package org.apache.commons.math.complex;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.complex.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.complex.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.complex.Complex;
import static org.junit.Assert.*;

public class StepDefs {
    private Complex complexNumber;
    private Complex result;

    @Given("a complex number with real part {double} and imaginary part {double}")
    public void a_complex_number_with_real_part_and_imaginary_part(double real, double imaginary) {
        this.complexNumber = new Complex(real, imaginary);
    }

    @When("I divide this complex number by Complex.ZERO")
    public void i_divide_this_complex_number_by_complex_zero() {
        try {
            this.result = complexNumber.divide(Complex.ZERO);
        } catch (Exception e) {
            // Catch any exception that might occur during division by zero
            this.result = null;
        }
    }

    @Then("the result should be Complex.INF")
    public void the_result_should_be_complex_inf() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be infinite", result.isInfinite());
    }

    @Given("the complex number I \\(0.0 \\+ 1.0i)")
    public void the_complex_number_i(double real, double imaginary) {
        this.complexNumber = new Complex(0.0, 1.0);
    }

    @When("I compute the inverse tangent \\(atan\\) of I")
    public void i_compute_the_inverse_tangent_atan_of_i() {
        try {
            this.result = complexNumber.atan();
        } catch (Exception e) {
            // Catch any exception that might occur during atan computation
            this.result = null;
        }
    }

    @Then("the result should be infinite")
    public void the_result_should_be_infinite() {
        assertNotNull("Result should not be null", result);
        assertTrue("Result should be infinite", result.isInfinite());
    }
}

